33	function calculateItemSurcharges(items: any[]): number {
34	  let surcharges = 0;
35	  for (const item of items) {
36	    const itemBase = MAIN_ITEM_PREMIUMS[item.type] || 0;
37	    if (item.cursed) {
38	      surcharges += itemBase * 0.5;
39	    }
40	  }
41	  return surcharges;
